		function ACCEPT()
{   
	var np, nSQL, docDatos;
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();  
 	docDatos = new NomadXML(nSQL.Get(Ctrl("main").getResource("qryDatos"), "<PARAM id=\""+Ctrl("oi_personal_emp").GetXValue()+"\" />"));		

 	Ctrl('oi_empresa').SetXValue(docDatos.GetAttr("oi_empresa"));
 	Ctrl('oi_personal').SetXValue(docDatos.GetAttr("oi_personal"));

 	if (CtrlExists('chkUniOrg') 		&& Ctrl('chkUniOrg').TypedValue())			{ if (Ctrl('chkPosicion'))	{ Ctrl('chkPosicion').SetCValue(1);} }
 	if (CtrlExists('chkBsCargo') 		&& Ctrl('chkBsCargo').TypedValue())			{ if (Ctrl('chkPosicion'))	{ Ctrl('chkPosicion').SetCValue(1);} }
 	if (CtrlExists('chkEPP') 				&& Ctrl('chkEPP').TypedValue())					{ if (Ctrl('chkPosicion'))	{ Ctrl('chkPosicion').SetCValue(1);} }
 	if (CtrlExists('chkUniformes') 	&& Ctrl('chkUniformes').TypedValue())		{ if (Ctrl('chkPosicion'))	{ Ctrl('chkPosicion').SetCValue(1);} }
 	if (CtrlExists('chkBeneficios') && Ctrl('chkBeneficios').TypedValue())	{ if (Ctrl('chkPosicion'))	{ Ctrl('chkPosicion').SetCValue(1);} }
 	if (CtrlExists('chkIngresos') 	&& Ctrl('chkIngresos').TypedValue())		{ if (Ctrl('chkPosicion'))	{ Ctrl('chkPosicion').SetCValue(1);} }
 	if (CtrlExists('chkLicencias') 	&& Ctrl('chkLicencias').TypedValue())		{ if (Ctrl('chkPosicion'))	{ Ctrl('chkPosicion').SetCValue(1);} }


  	Ctrl('chkTrayectorias').SetXValue(0);
  	if (CtrlExists('tray_categ') 		&& Ctrl('tray_categ').TypedValue())				{ Ctrl('chkTrayectorias').SetXValue(1); }
  	if (CtrlExists('tray_costo') 		&& Ctrl('tray_costo').TypedValue())				{ Ctrl('chkTrayectorias').SetXValue(1); }
  	if (CtrlExists('tray_contrato') && Ctrl('tray_contrato').TypedValue())		{ Ctrl('chkTrayectorias').SetXValue(1); }
  	if (CtrlExists('tray_puesto') 	&& Ctrl('tray_puesto').TypedValue())			{ Ctrl('chkTrayectorias').SetXValue(1); }
  	if (CtrlExists('tray_posicion') && Ctrl('tray_posicion').TypedValue())		{ Ctrl('chkTrayectorias').SetXValue(1); }
  	if (CtrlExists('tray_equipo') 	&& Ctrl('tray_equipo').TypedValue())			{ Ctrl('chkTrayectorias').SetXValue(1); }
  	if (CtrlExists('tray_calen') 		&& Ctrl('tray_calen').TypedValue())				{ Ctrl('chkTrayectorias').SetXValue(1); }
  	if (CtrlExists('tray_tipos') 		&& Ctrl('tray_tipos').TypedValue())				{ Ctrl('chkTrayectorias').SetXValue(1); }  
  	if (CtrlExists('tray_remun') 		&& Ctrl('tray_remun').TypedValue())				{ Ctrl('chkTrayectorias').SetXValue(1); } 


  	Ctrl('chkMedicina').SetXValue(0);
		if (CtrlExists('med_histclin') 		&& Ctrl('med_histclin').TypedValue()) 		{ Ctrl('chkMedicina').SetXValue(1); }
		if (CtrlExists('med_antec') 			&& Ctrl('med_antec').TypedValue()) 				{ Ctrl('chkMedicina').SetXValue(1); }
		if (CtrlExists('med_exam') 				&& Ctrl('med_exam').TypedValue()) 				{ Ctrl('chkMedicina').SetXValue(1); }


		Ctrl('chkLaborales').SetXValue(0); 		
		if (CtrlExists('chkDatosContrato') && Ctrl('chkDatosContrato').TypedValue()) { Ctrl('chkLaborales').SetXValue(1); } 
		if (CtrlExists('chkRelLaboral') 	 && Ctrl('chkRelLaboral').TypedValue()) 	 { Ctrl('chkLaborales').SetXValue(1); }
		if (CtrlExists('chkAfiliacion')	 && Ctrl('chkAfiliacion').TypedValue()) 	 { Ctrl('chkLaborales').SetXValue(1); }
		if (CtrlExists('chkPosicion')		 && Ctrl('chkPosicion').TypedValue()) 		 { Ctrl('chkLaborales').SetXValue(1); }
		if (CtrlExists('chkUniOrg')			 && Ctrl('chkUniOrg').TypedValue()) 			 { Ctrl('chkLaborales').SetXValue(1); }
		if (CtrlExists('chkBsCargo')			 && Ctrl('chkBsCargo').TypedValue()) 			 { Ctrl('chkLaborales').SetXValue(1); }
		if (CtrlExists('chkEPP')					 && Ctrl('chkEPP').TypedValue()) 					 { Ctrl('chkLaborales').SetXValue(1); }
		if (CtrlExists('chkUniformes') 	 && Ctrl('chkUniformes').TypedValue()) 		 { Ctrl('chkLaborales').SetXValue(1); }
		if (CtrlExists('chkBeneficios') 	 && Ctrl('chkBeneficios').TypedValue()) 	 { Ctrl('chkLaborales').SetXValue(1); }
		if (CtrlExists('chkIngresos')		 && Ctrl('chkIngresos').TypedValue()) 	 	 { Ctrl('chkLaborales').SetXValue(1); }
		if (CtrlExists('chkLicencias')	   && Ctrl('chkLicencias').TypedValue()) 		 { Ctrl('chkLaborales').SetXValue(1); }


  	Ctrl("main").DoEvent("acept");	   
  return true;
}
function sel()
{
	if (Ctrl('AUXILIAR').GetCValue() != 1)
	{
		Ctrl('chkDatosReferenciales').SetCValue(1);
		if (CtrlExists('chkDocumentos')) 			{ Ctrl('chkDocumentos').SetCValue(1);}
		if (CtrlExists('chkDomicilios')) 			{ Ctrl('chkDomicilios').SetCValue(1);}
		if (CtrlExists('chkEstudios')) 				{ Ctrl('chkEstudios').SetCValue(1);}
