		if (CtrlExists('chkCursos')) 					{ Ctrl('chkCursos').SetCValue(1);} 
		if (CtrlExists('chkCompetencias')) 		{ Ctrl('chkCompetencias').SetCValue(1);}
		if (CtrlExists('chkAntecedentesLab'))	{ Ctrl('chkAntecedentesLab').SetCValue(1);}
		if (CtrlExists('chkDatosFam')) 				{ Ctrl('chkDatosFam').SetCValue(1);}
		if (CtrlExists('chkDatosContrato')) 	{ Ctrl('chkDatosContrato').SetCValue(1);}
		if (CtrlExists('chkRelLaboral')) 			{ Ctrl('chkRelLaboral').SetCValue(1);}
		if (CtrlExists('chkAfiliacion')) 			{ Ctrl('chkAfiliacion').SetCValue(1);}
		if (CtrlExists('chkPosicion')) 				{ Ctrl('chkPosicion').SetCValue(1);}
		if (CtrlExists('chkUniOrg')) 					{ Ctrl('chkUniOrg').SetCValue(1);}
		if (CtrlExists('chkBsCargo')) 				{ Ctrl('chkBsCargo').SetCValue(1);}
		if (CtrlExists('chkEPP')) 						{ Ctrl('chkEPP').SetCValue(1);}
		if (CtrlExists('chkUniformes')) 			{ Ctrl('chkUniformes').SetCValue(1);}
		if (CtrlExists('chkBeneficios')) 			{ Ctrl('chkBeneficios').SetCValue(1);}
		if (CtrlExists('chkIngresos')) 				{ Ctrl('chkIngresos').SetCValue(1);}
		if (CtrlExists('chkLicencias')) 			{ Ctrl('chkLicencias').SetCValue(1);}
		Ctrl('chkTrayectorias').SetXValue(1);
		if (CtrlExists('tray_categ')) 				{ Ctrl('tray_categ').SetCValue(1);}
		if (CtrlExists('tray_costo')) 				{ Ctrl('tray_costo').SetCValue(1);}
		if (CtrlExists('tray_contrato')) 			{ Ctrl('tray_contrato').SetCValue(1);}
		if (CtrlExists('tray_puesto')) 				{ Ctrl('tray_puesto').SetCValue(1);}
		if (CtrlExists('tray_posicion')) 			{ Ctrl('tray_posicion').SetCValue(1);}
		if (CtrlExists('tray_equipo')) 				{ Ctrl('tray_equipo').SetCValue(1);}
		if (CtrlExists('tray_calen')) 				{ Ctrl('tray_calen').SetCValue(1);}
		if (CtrlExists('tray_tipos')) 				{ Ctrl('tray_tipos').SetCValue(1);}
		if (CtrlExists('tray_remun')) 				{ Ctrl('tray_remun').SetCValue(1);}		  		
		Ctrl('AUXILIAR').SetCValue(1);
		selaux();
	}
}


