function sel1()		
		{
			if (Ctrl('sel1_personales').GetXValue() =="0")
			{				
				Ctrl('chkDatosReferenciales').SetCValue(1);
				if (CtrlExists('chkDocumentos')) 			{ Ctrl('chkDocumentos').SetCValue(1);}
				if (CtrlExists('chkDomicilios')) 			{ Ctrl('chkDomicilios').SetCValue(1);}
				if (CtrlExists('chkEstudios')) 				{ Ctrl('chkEstudios').SetCValue(1);}
				if (CtrlExists('chkIdiomas')) 				{ Ctrl('chkIdiomas').SetCValue(1);}
				if (CtrlExists('chkCursos')) 					{ Ctrl('chkCursos').SetCValue(1);}
				if (CtrlExists('chkCompetencias')) 		{ Ctrl('chkCompetencias').SetCValue(1);}
				if (CtrlExists('chkAntecedentesLab'))	{ Ctrl('chkAntecedentesLab').SetCValue(1);}
				if (CtrlExists('chkDatosFam')) 				{ Ctrl('chkDatosFam').SetCValue(1);}
				Ctrl('sel1_personales').SetXValue(1);  		
			}else
			{				
				Ctrl('chkDatosReferenciales').SetCValue(0);
				if (CtrlExists('chkDocumentos')) 			{ Ctrl('chkDocumentos').SetCValue(0);}
				if (CtrlExists('chkDomicilios')) 			{ Ctrl('chkDomicilios').SetCValue(0);}
				if (CtrlExists('chkEstudios')) 				{ Ctrl('chkEstudios').SetCValue(0);}
				if (CtrlExists('chkIdiomas')) 				{ Ctrl('chkIdiomas').SetCValue(0);}
				if (CtrlExists('chkCursos')) 					{ Ctrl('chkCursos').SetCValue(0);}
				if (CtrlExists('chkCompetencias')) 		{ Ctrl('chkCompetencias').SetCValue(0);}
				if (CtrlExists('chkAntecedentesLab'))	{ Ctrl('chkAntecedentesLab').SetCValue(0);}
				if (CtrlExists('chkDatosFam')) 				{ Ctrl('chkDatosFam').SetCValue(0);}
				Ctrl('sel1_personales').SetXValue(0);												
			}
		}

