function onload()
{
	if(Ctrl('cb_confidenciales')!=undefined)
	{
	 	if(!Ctrl('cb_confidenciales').GetEnabled())
	 	{
	 		Ctrl('cb_confidenciales').SetXValue('NC');
	 	}                                          
	 	else
	 	{         
	 		if(Ctrl('cb_confidenciales').GetXValue()=='')
	 			Ctrl('cb_confidenciales').SetXValue('T');
	 	}  

	 	Ctrl('oi_personal_emp').SetWhere(Ctrl('cb_confidenciales').GetXValue());
	}    
}         

function onchange()
{      
	if(Ctrl('cb_confidenciales')!=undefined)
	{
 	   Ctrl('oi_personal_emp').SetWhere(Ctrl('cb_confidenciales').GetXValue());
 	}
}
